customCSS:
/* Convergent Spiral — Where Phi Meets Infinity */
@import url('https://fonts.googleapis.com/css2?family=Cinzel:wght@400;500;600;700&family=Inter:wght@300;400;500;600&family=Fira+Code&display=swap');

.cyber-glow {
  background:
    radial-gradient(ellipse 610px 377px at 38.2% 0%, rgba(200, 152, 24, 0.12), transparent),
    radial-gradient(ellipse 377px 233px at 61.8% 100%, rgba(144, 112, 208, 0.08), transparent);
}

.cyber-particles { opacity: 0.3; }

.stat-card {
  border: 1px solid rgba(200, 152, 24, 0.14);
  backdrop-filter: blur(10px);
  background: rgba(24, 21, 32, 0.88);
}

.stat-card::before {
  background: linear-gradient(137.5deg, #c89818, #ffe030, #9070d0);
  height: 2px;
}

.stat-card:hover {
  border-color: rgba(200, 152, 24, 0.35);
  box-shadow: 0 4px 28px rgba(200, 152, 24, 0.15);
}

.stat-value {
  text-shadow: 0 0 18px rgba(200, 152, 24, 0.45);
}

.celebration-title {
  background: linear-gradient(137.5deg, #c89818, #ffe030, #9070d0);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  text-shadow: none;
  filter: drop-shadow(0 0 20px rgba(200, 152, 24, 0.4));
}

.miner-card, .health-card, .lifetime-card {
  border: 1px solid rgba(200, 152, 24, 0.10);
  background: rgba(24, 21, 32, 0.75);
}

.miner-card:hover {
  border-color: rgba(144, 112, 208, 0.25);
}

.logo {
  color: #c89818;
  text-shadow: 0 0 20px rgba(200, 152, 24, 0.4);
}
